INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8ebda338-ee67-4ffb-84cd-33ac2dc7a099',
  '00000000-0000-0000-0000-000000000001',
  $escape$Docker Images vs Containers — Layers, Copy-on-Write, and What Actually Lives on Disk$escape$,
  $escape$A Docker image is a read-only stack of layers, each produced by a Dockerfile instruction. Run `docker image inspect nginx:alpine` and you'll see `RootFS.Layers` — each a SHA256 content-addressed tarball stored under `/var/lib/docker/overlay2/`. When you run `docker run`, Docker creates a thin writable layer on top via OverlayFS (the default storage driver). That writable layer is the container. The image layers are never modified — copy-on-write (CoW) kicks in the moment a container writes to a file that exists in a lower layer: OverlayFS copies the file up to the writable layer first, then modifies it. This is why two containers sharing the same image consume almost no extra disk for reads. It also explains why writing large files inside a container is slower than on the host — the CoW copy-up has overhead. Keep image layers small and ordered by change frequency (deps before app code) to maximize layer cache hits during builds. Use `docker diff <container>` to inspect exactly which files a running container has mutated.$escape$,
  $escape$# Inspect layers of an image
docker image inspect nginx:alpine --format '{{json .RootFS.Layers}}' | jq .

# Run two containers from the same image — shared read layers, isolated write layers
docker run -d --name c1 nginx:alpine
docker run -d --name c2 nginx:alpine

# See CoW in action: mutate a file in c1 only
docker exec c1 sh -c 'echo hello > /usr/share/nginx/html/index.html'

# diff shows only c1's writable layer changed
docker diff c1   # C /usr/share/nginx/html/index.html
docker diff c2   # (empty — image layer untouched)

# Check disk usage breakdown: image layers vs container writable layers
docker system df -v$escape$,
  $escape$bash$escape$,
