INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '98ac4ba8-5646-468e-9598-ba08ab412f80',
  '00000000-0000-0000-0000-000000000001',
  $escape$Docker Dockerfile Best Practices — Layer Caching, Multi-Stage Builds, and Minimal Base Images$escape$,
  $escape$Every RUN, COPY, and ADD instruction creates a new layer. Docker invalidates cache from the first changed layer downward — so order matters. Put infrequently changing instructions (installing OS deps) before frequently changing ones (copying source code). Never COPY . . before installing dependencies; copy only the lockfile first, run the install, then copy source.

Multi-stage builds cut final image size dramatically. Use a fat builder stage with full toolchains, then COPY --from=builder only the compiled artifact into a minimal runtime stage. A Go binary that builds in a 1.22-golang image ships in scratch. A Node app built in node:20 can run in node:20-alpine or even a distroless image.

For base images, prefer -alpine or Google's distroless over full Debian/Ubuntu. Alpine images are ~5 MB vs ~80 MB for debian:slim. Distroless images contain no shell, package manager, or utilities — shrinking the attack surface to near zero. Pin exact digest tags (FROM node:20.11.0-alpine3.19@sha256:...) in production to prevent silent upstream mutations.$escape$,
  $escape$# Stage 1: build
FROM node:20.11.0-alpine3.19 AS builder
WORKDIR /app
COPY package.json package-lock.json ./
RUN npm ci --omit=dev
COPY . .
RUN npm run build

# Stage 2: runtime (distroless)
FROM gcr.io/distroless/nodejs20-debian12
WORKDIR /app
COPY --from=builder /app/dist ./dist
COPY --from=builder /app/node_modules ./node_modules
CMD ["dist/server.js"]$escape$,
