INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '40530c52-a359-4a57-9c78-ae9e49157f72',
  '00000000-0000-0000-0000-000000000001',
  $escape$Docker Networking — Bridge vs Host vs Overlay Networks and Built-in DNS$escape$,
  $escape$Docker ships four production-relevant network drivers, each with a distinct routing model. Bridge (default) creates an isolated virtual switch per-daemon; containers get a private subnet (172.17.0.0/16) and reach the host via NAT. Crucially, user-defined bridge networks enable Docker's embedded DNS: containers resolve each other by service name, no `/etc/hosts` hacking needed. Host mode bypasses the network namespace entirely — the container binds directly to the host's NIC, eliminating NAT overhead but sacrificing isolation. Overlay spans multiple Docker daemons (Swarm mode), stitching distributed containers into a single L2 fabric with automatic VXLAN encapsulation. Port publishing (`-p 8080:80`) is your NodePort equivalent: Docker inserts an iptables DNAT rule routing host traffic into the container. For production load-balancing, pair Overlay with Swarm's built-in VIP routing mesh — each service gets a stable virtual IP, and the Swarm load-balances across replicas transparently. On user-defined networks, `docker exec app curl http://db:5432` resolves via 127.0.0.11 (Docker's internal DNS resolver), not broadcast.$escape$,
  $escape$# docker-compose.yml — explicit network with DNS-based service discovery
services:
  api:
    image: myapp:latest
    ports:
      - "8080:80"        # iptables DNAT → NodePort analogue
    networks:
      - backend

  db:
    image: postgres:16
    environment:
      POSTGRES_PASSWORD: secret
    networks:
      - backend           # reachable as 'db:5432' via Docker DNS

networks:
  backend:
    driver: bridge        # swap for 'overlay' in Swarm mode
    ipam:
      config:
        - subnet: 10.10.0.0/24$escape$,
  $escape$bash$escape$,
