INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ddc69956-93b6-43a0-b0d3-2ddb79a4f686',
  '00000000-0000-0000-0000-000000000001',
  $escape$Docker Secrets & Configs — Externalizing Config and Encrypting Secrets at Rest in Swarm$escape$,
  $escape$Docker Swarm's native secret and config objects externalize configuration without baking credentials into images or leaking them through environment variables. Secrets are encrypted at rest using AES-256-GCM inside the Raft consensus store and delivered to authorized tasks via an in-memory tmpfs mount at `/run/secrets/<name>` — they never touch disk on the worker node.

Configs work identically but store plaintext — use them for non-sensitive data like `nginx.conf` or `prometheus.yml`, Docker's equivalent of Kubernetes ConfigMaps. Both are version-immutable: an update means creating a new secret/config object and performing a rolling service update.

Access is declared explicitly per service. A container without `--secret db_password` cannot read the value even when collocated on the same node — a hard isolation boundary that env vars can't offer (env vars leak into child processes, `/proc`, and crash dumps).

For standalone Docker outside Swarm, the encrypted Raft store doesn't exist. Docker Compose's `secrets:` block backed by host files works for local dev, but encryption at rest is your OS's responsibility — pair it with a secrets manager like Vault or AWS SSM Parameter Store for production.$escape$,
  $escape$# Create a secret — encrypted at rest in Swarm's Raft store
echo "s3cr3t-db-pass" | docker secret create db_password -

# Create a config — plaintext, for non-sensitive externalized config
docker config create nginx_conf ./nginx.conf

# Deploy service with secret + config wired in
docker service create \
  --name api \
  --secret db_password \
  --config source=nginx_conf,target=/etc/nginx/nginx.conf \
  myapp:latest

# Secret is readable inside the container at:
# /run/secrets/db_password  (tmpfs, read-only, never hits disk)$escape$,
  $escape$bash$escape$,
