INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1c4db082-bb5c-40bc-9951-47977a4cfa5b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Docker Resource Management — Limits, Reservations, and Surviving OOMKill$escape$,
  $escape$Docker's `--memory` flag sets a hard ceiling — breach it and the Linux OOM killer terminates your container instantly. `--memory-reservation` is the soft limit: the kernel may reclaim memory from the container under host pressure without killing it. These map loosely to Kubernetes requests/limits, but operate at the cgroup level directly.

Without explicit `--memory-swap`, Docker allows 2× your memory limit in swap. Set `--memory-swap` equal to `--memory` to disable swap entirely and surface memory leaks immediately rather than masking them.

Three practical QoS tiers emerge: containers with no constraints (BestEffort — OOM-killed first), those with only `--memory` (Burstable — killed when limit is hit), and containers with both `--memory` and `--memory-reservation` set (Guaranteed-like — kernel reclaims before killing).

For CPU, `--cpus` caps absolute core usage. `--cpu-shares` (default 1024) sets relative scheduling weight under contention — a container at 512 shares gets half the CPU of one at 1024 when both are busy.

Monitor live via `docker stats` or read `/sys/fs/cgroup/memory/memory.usage_in_bytes` directly. Never set `--oom-kill-disable` in production — it deflects kills onto other host processes.$escape$,
  $escape$docker run -d \
  --name api-server \
  --memory="512m" \
  --memory-reservation="384m" \
  --memory-swap="512m" \
  --cpus="1.5" \
  --cpu-shares=1024 \
  my-api:latest

# Verify live resource usage and OOM pressure
docker stats api-server --no-stream$escape$,
  $escape$bash$escape$,
