INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ceff7dae-9959-4219-9997-8019b440b2df',
  '00000000-0000-0000-0000-000000000001',
  $escape$Docker User Namespaces — Enforcing Least Privilege in Multi-Tenant Clusters$escape$,
  $escape$Running multiple tenants on shared Docker infrastructure without user namespace remapping means every `root` inside a container maps to `root` on the host — a container escape becomes a full host compromise. Enable `userns-remap` in `daemon.json` to remap container UIDs/GIDs to a subordinate unprivileged range. With `"userns-remap": "default"`, Docker auto-creates a `dockremap` user and maps UID 0 inside the container to UID 100000+ outside — a kernel-enforced boundary. Layer this with per-tenant bridge networks to enforce network namespace isolation: containers on separate networks cannot communicate even if they share a host. Add `--cap-drop ALL --cap-add <explicit>` per workload to strip capabilities that aren't needed — most app containers only need `NET_BIND_SERVICE`. Never bind-mount shared host paths across tenants; use isolated named volumes instead. Verify the remapping is live: `id` inside the container returns `uid=0`, but `ps aux` on the host shows UID `100000+`. This three-layer model — user namespaces, network namespaces, capability restrictions — gives you meaningful tenant boundaries without Kubernetes overhead.$escape$,
  $escape$# /etc/docker/daemon.json
# { "userns-remap": "default" }
# systemctl restart docker

# Isolated per-tenant networks
docker network create --driver bridge tenant-a-net
docker network create --driver bridge tenant-b-net

# Least-privilege container for tenant-a
docker run -d --name svc-a \
  --network tenant-a-net \
  --cap-drop ALL --cap-add NET_BIND_SERVICE \
  --read-only --tmpfs /tmp \
  nginx:alpine

# Verify: root inside != root outside
docker exec svc-a id        # uid=0(root) inside
ps aux | grep nginx          # uid=100000 on host$escape$,
  $escape$bash$escape$,
