INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6de35c64-d712-40a8-bc14-1ac2da2075e4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Docker Network Isolation — Controlling Container-to-Container Traffic and Ingress$escape$,
  $escape$Docker enforces container isolation through named networks backed by Linux bridge devices and iptables chains. Every `docker network create` spins up a new bridge (e.g., `br-a1b2c3d4`) and inserts FORWARD rules controlling cross-network traffic.

By default, containers on the same user-defined bridge network communicate freely via Docker's embedded DNS — containers resolve each other by service name. Containers on different networks cannot reach each other at all without explicit multi-network membership.

The `internal: true` flag on a network inserts an iptables DROP rule on the FORWARD chain for external IPs, blocking all outbound routing. Use this to enforce strict ingress-only topologies: your reverse proxy sits on a public-facing network, your app bridges both, and your database lives exclusively on the internal network — unreachable from any external interface.

For ingress, Traefik's Docker provider reads container labels at runtime and dynamically wires HTTP routing rules without a restart. Only the ingress container exposes host ports — upstream services stay unexposed, communicating purely over Docker's virtual bridge.$escape$,
  $escape$services:
  traefik:
    image: traefik:v3.0
    command: --providers.docker=true --entrypoints.web.address=:80
    ports:
      - "80:80"
    volumes:
      - /var/run/docker.sock:/var/run/docker.sock
    networks: [public]

  api:
    image: myapp-api:latest
    labels:
      - "traefik.http.routers.api.rule=Host(`api.local`)"
      - "traefik.http.services.api.loadbalancer.server.port=8080"
    networks: [public, internal]  # bridges both; only ingress point

  db:
    image: postgres:16
    networks: [internal]           # no host ports; zero external exposure

networks:
  public: {}
  internal:
    internal: true                 # iptables DROP on FORWARD for external IPs$escape$,
  $escape$bash$escape$,
